class SecureUuidGenerator {
  static final Random _random = Random.secure();

  static String generateV4() {
    final bytes = Uint8List(16);
    
    for (int i = 0; i < 16; i++) {
      bytes[i] = _random.nextInt(256);
    }
    
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;
    
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    
    return '${hex.substring(0, 8)}-${hex.substring(8, 12)}-${hex.substring(12, 16)}-${hex.substring(16, 20)}-${hex.substring(20, 32)}';
  }

  static String generateShort() {
    final bytes = Uint8List(8);
    for (int i = 0; i < 8; i++) {
      bytes[i] = _random.nextInt(256);
    }
    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  static String generateTimestampBased() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final randomBytes = Uint8List(8);
    for (int i = 0; i < 8; i++) {
      randomBytes[i] = _random.nextInt(256);
    }
    
    final timestampHex = timestamp.toRadixString(16).padLeft(12, '0');
    final randomHex = randomBytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    
    return '$timestampHex-$randomHex';
  }

  static bool isValidUuid(String uuid) {
    final pattern = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return pattern.hasMatch(uuid);
  }
}

class OfflineDataEntry {
  final String id;
  final String data;
  final DateTime createdAt;
  final bool synced;

  OfflineDataEntry({
    String? id,
    required this.data,
    DateTime? createdAt,
    this.synced = false,
  })  : id = id ?? SecureUuidGenerator.generateV4(),
        createdAt = createdAt ?? DateTime.now();

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'data': data,
      'createdAt': createdAt.toIso8601String(),
      'synced': synced,
    };
  }

  factory OfflineDataEntry.fromJson(Map<String, dynamic> json) {
    return OfflineDataEntry(
      id: json['id'],
      data: json['data'],
      createdAt: DateTime.parse(json['createdAt']),
      synced: json['synced'] ?? false,
    );
  }

  OfflineDataEntry copyWith({
    String? id,
    String? data,
    DateTime? createdAt,
    bool? synced,
  }) {
    return OfflineDataEntry(
      id: id ?? this.id,
      data: data ?? this.data,
      createdAt: createdAt ?? this.createdAt,
      synced: synced ?? this.synced,
    );
  }
}

class OfflineDataManager {
  final List<OfflineDataEntry> _entries = [];

  String createEntry(String data) {
    final entry = OfflineDataEntry(data: data);
    _entries.add(entry);
    return entry.id;
  }

  OfflineDataEntry? getEntry(String id) {
    try {
      return _entries.firstWhere((entry) => entry.id == id);
    } catch (e) {
      return null;
    }
  }

  List<OfflineDataEntry> getUnsyncedEntries() {
    return _entries.where((entry) => !entry.synced).toList();
  }

  void markAsSynced(String id) {
    final index = _entries.indexWhere((entry) => entry.id == id);
    if (index != -1) {
      _entries[index] = _entries[index].copyWith(synced: true);
    }
  }

  void markAllAsSynced() {
    for (int i = 0; i < _entries.length; i++) {
      _entries[i] = _entries[i].copyWith(synced: true);
    }
  }

  List<OfflineDataEntry> getAllEntries() {
    return List.unmodifiable(_entries);
  }

  void deleteEntry(String id) {
    _entries.removeWhere((entry) => entry.id == id);
  }

  void clear() {
    _entries.clear();
  }

  int get totalEntries => _entries.length;
  int get unsyncedCount => _entries.where((entry) => !entry.synced).length;
}

